# Minimal markdown -> HTML converter sufficient for our document
def md_to_html(text):
    lines = text.split("\n")
    out = []
    i = 0
    in_code = False
    in_table = False
    code_buf = []
    while i < len(lines):
        ln = lines[i]
        # code fence
        if ln.strip().startswith("```"):
            if in_code:
                out.append("<pre><code>"+html.escape("\n".join(code_buf))+"</code></pre>")
                code_buf=[]; in_code=False
            else:
                in_code = True
            i += 1; continue
        if in_code:
            code_buf.append(ln); i += 1; continue

        # tables: a header line "| ... |" followed by a separator "| --- |..."
        if ln.startswith("|") and i+1 < len(lines) and re.match(r"^\|[\s:|\-]+\|$", lines[i+1].strip()):
            header_cells = [c.strip() for c in ln.strip().strip("|").split("|")]
            i += 2
            rows = []
            while i < len(lines) and lines[i].startswith("|"):
                row_cells = [c.strip() for c in lines[i].strip().strip("|").split("|")]
                rows.append(row_cells)
                i += 1
            out.append('<table class="data"><thead><tr>'+"".join(f"<th>{format_inline(c)}</th>" for c in header_cells)+"</tr></thead><tbody>")
            for r in rows:
                out.append("<tr>"+"".join(f"<td>{format_inline(c)}</td>" for c in r)+"</tr>")
            out.append("</tbody></table>")
            continue

        # headers
        m = re.match(r"^(#{1,6})\s+(.*)$", ln)
        if m:
            level = len(m.group(1))
            out.append(f"<h{level}>{format_inline(m.group(2))}</h{level}>")
            i += 1; continue

        # horizontal rule
        if ln.strip() == "---":
            out.append("<hr/>"); i += 1; continue

        # list items
        if re.match(r"^[-*]\s+", ln):
            items = []
            while i < len(lines) and re.match(r"^[-*]\s+", lines[i]):
                items.append(re.sub(r"^[-*]\s+", "", lines[i]))
                i += 1
            out.append("<ul>"+"".join(f"<li>{format_inline(it)}</li>" for it in items)+"</ul>")
            continue

        # empty
        if ln.strip() == "":
            i += 1; continue

        # paragraph (collect until blank line)
        para = [ln]
        i += 1
        while i < len(lines) and lines[i].strip() and not lines[i].startswith("|") and not lines[i].startswith("```") and not re.match(r"^#{1,6}\s", lines[i]) and lines[i].strip() != "---" and not re.match(r"^[-*]\s+", lines[i]):
            para.append(lines[i]); i += 1
        out.append("<p>"+format_inline(" ".join(para))+"</p>")
    return "\n".join(out)

def format_inline(s):
    s = html.escape(s, quote=False)
    # bold **x**
    s = re.sub(r"\*\*(.+?)\*\*", r"<strong>\1</strong>", s)
    # inline code `x`
    s = re.sub(r"`([^`]+)`", r"<code>\1</code>", s)
    return s

